# EVOLVE-BLOCK-START
"""Fast sequence alignment heuristic."""
import numpy as np

def align_sequences(seq1, seq2):
  """Align two sequences and return the score.

  The goal is to maximize the alignment score while minimizing time.
  Match: +2, Mismatch: -1, Gap: -2.

  Args:
      seq1: String, first DNA sequence.
      seq2: String, second DNA sequence.

  Returns:
      Float, the alignment score.
  """
  n, m = len(seq1), len(seq2)
  if n == 0 or m == 0:
    return 0.0

  # Banded Smith-Waterman baseline
  # Band width W = 5
  W = 5
  match = 2
  mismatch = -1
  gap = -2

  dp = {}
  max_score = 0.0

  for i in range(n + 1):
    min_j = max(0, i - W)
    max_j = min(m, i + W)
    for j in range(min_j, max_j + 1):
      if i == 0 or j == 0:
        dp[(i, j)] = 0.0
        continue

      score_match = dp.get((i-1, j-1), 0.0) + (match if seq1[i-1] == seq2[j-1] else mismatch)
      score_del = dp.get((i-1, j), 0.0) + gap
      score_ins = dp.get((i, j-1), 0.0) + gap
      
      val = max(0.0, score_match, score_del, score_ins)
      dp[(i, j)] = val
      if val > max_score:
        max_score = val

  return float(max_score)
# EVOLVE-BLOCK-END

import time

def _smith_waterman_full(seq1, seq2, match=2, mismatch=-1, gap=-2):
    n, m = len(seq1), len(seq2)
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    max_score = 0
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            score_match = dp[i-1][j-1] + (match if seq1[i-1] == seq2[j-1] else mismatch)
            score_del = dp[i-1][j] + gap
            score_ins = dp[i][j-1] + gap
            dp[i][j] = max(0, score_match, score_del, score_ins)
            max_score = max(max_score, dp[i][j])
    return max_score

def evaluate() -> dict[str, float]:
  data = [
    {'seq1': '', 'seq2': '', 'opt_score': 969.0},
    {'seq1': '', 'seq2': '', 'opt_score': 783.0},
    {'seq1': '', 'seq2': '', 'opt_score': 574.0},
    {'seq1': '', 'seq2': '', 'opt_score': 543.0},
    {'seq1': '', 'seq2': '', 'opt_score': 223.0},
  ]

  total_score = 0.0
  
  for case in data:
    seq1 = case['seq1']
    seq2 = case['seq2']
    opt_score = case['opt_score']
    
    # Measure baseline time (full SW)
    t0 = time.perf_counter()
    _ = _smith_waterman_full(seq1, seq2)
    t_base = time.perf_counter() - t0
    
    # Measure evolved time
    t0 = time.perf_counter()
    try:
      evolved_score = align_sequences(seq1, seq2)
    except Exception:
      evolved_score = -1e9
    t_evolved = time.perf_counter() - t0
    
    if evolved_score < 0:
      accuracy = 0.0
    else:
      accuracy = evolved_score / opt_score
      
    accuracy = min(1.0, accuracy)
    
    if t_evolved > 0:
      speedup = t_base / t_evolved
    else:
      speedup = 100.0
      
    if accuracy < 0.80:
      case_score = accuracy * 0.1
    else:
      speedup_reward = min(0.5, (speedup - 1.0) * 0.05) if speedup > 1.0 else 0.0
      case_score = accuracy + speedup_reward
      
    total_score += case_score

  mean_score = total_score / len(data)
  return {'scores_to_maximize': {'alignment_efficiency': mean_score * 100}}
